To refactor the authentication middleware to use async/await instead of callbacks, I will first provide a sample implementation of the middleware, then refactor it, and finally validate the changes using appropriate testing methods.

### Step 1: Sample Authentication Middleware Implementation

Here’s a basic example of an authentication middleware using callbacks:

```javascript
const jwt = require('jsonwebtoken');

function authenticate(req, res, next) {
    const token = req.headers['authorization'];

    if (!token) {
        return res.status(403).send('No token provided.');
    }

    jwt.verify(token, 'your-secret-key', (err, decoded) => {
        if (err) {
            return res.status(500).send('Failed to authenticate token.');
        }
        req.userId = decoded.id;
        next();
    });
}

module.exports = authenticate;
```

### Step 2: Refactor to Use Async/Await

Now, I will refactor the above middleware to use async/await:

```javascript
const jwt = require('jsonwebtoken');

async function authenticate(req, res, next) {
    const token = req.headers['authorization'];

    if (!token) {
        return res.status(403).send('No token provided.');
    }

    try {
        const decoded = await jwt.verify(token, 'your-secret-key');
        req.userId = decoded.id;
        next();
    } catch (err) {
        return res.status(500).send('Failed to authenticate token.');
    }
}

module.exports = authenticate;
```

